import React, {useRef, useState, useEffect} from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'
import camera from '../components/static/camera.png'
import cancel from '../components/static/cancel.png'

const SellWrapper = styled.form `
display:flex;
flex-direction:column;
align-items:flex-start;
width:55%;
margin:70px auto;
`

const Head = styled.div ``

const Body = styled.div `
margin:40px 0;
`

const PhotoUploadSection = styled.div ``

const Title = styled.div `
font-size:1.8rem;
font-weight:900;
`

const SectionTitle = styled.div `
font-size:1.5rem;
font-weight:800;
letter-spacing:2px;
color:rgba(0,0,0,0.7);
`

const Details = styled.div ``

const GridWrapper =  styled.div `
display:grid;
grid-template-columns: auto auto;
grid-template-rows: auto auto;
grid-gap:60px 60px;
width:100%;
margin:30px 0;
`

const Detail = styled.div `
width:360px;
height:40px;
border:1px solid grey;
color:grey;
border-radius:6px;
font-size:0.9rem;
text-align:center;
line-height:40px;
`

const Item = styled.input `
width:360px;
height:40px;
border:1px solid grey;
color:grey;
border-radius:6px;
margin-top:30px;
box-sizing:border-box;
padding:0 10px;
`

const Inputdiv = styled.div `
width:360px;
height:40px;
border:1px solid grey;
color:grey;
border-radius:6px;
margin-top:30px;
box-sizing:border-box;
padding:0 10px;
`


const DescriptionInput = styled.textarea `
width:100%;
height:80px;
border:1px solid grey;
color:grey;
border-radius:6px;
margin-top:30px;
box-sizing:border-box;
`

const MoreDetail = styled.div ``

const Description = styled.div ``

const Photo = styled.div ``

const PhotoWrapper = styled.label `
width:220px;
height:300px;
display:inline-block;
background-color:rgba(240,240,240, 0.7);
border-radius:8px;
border:0;
background-image:url(${camera});
background-position:center;
background-size:initial;
background-repeat:no-repeat;
`

const PhotoInput = styled.input `
display:none;
`

const FooterWrapper = styled.div `
display:flex;
justify-content:flex-end;
align-items:center;
width:100%;
padding:0 20px;
box-sizing:border-box;
`


const Submit = styled.input `
width:100px;
height:50px;
background-color:rgb(50, 50, 50);
color:white;
border-radius:10px;
border:0;
text-align:center;
line-height:50px;
font-size:0.9rem;
font-weight:800;
`

const Draft = styled.div `
width:150px;
height:50px;
background-color:white;
color:#1C1C1C;
border-radius:10px;
border:2px solid #1C1C1C;
text-align:center;
line-height:50px;
margin-right:20px;
font-size:0.9rem;
font-weight:800;
`

const CancelIcon = styled.div `
position:absolute;
width:20px;
height:20px;
background-image:url(${cancel});
background-size:cover;
margin:5px;
display:block;
`

const PhotoWrapperSection = styled.div `
display:inline-block;
margin:20px;
`

const DepartmentAndCategory = styled.div `
width:360px;
border:1px solid grey;
border-radius:4px;
position:absolute;
background-color:white;
${props => props.dropdownActive ? null: 'display:none'};
`

const Dropdown = styled.div `
width:360px;
border:1px solid grey;
border-radius:4px;
position:absolute;
background-color:white;
display:block;
display:none;
box-sizing:border-box;
`

const Option = styled.div `
display:flex;
justify-content:space-between;
box-sizing:border-box;
align-items:center;
padding:0px 5px;
box-sizing:border-box;
font-size:0.9rem;
font-weight:normal;
color:grey;
line-height:40px;
&:hover {
	cursor:pointer;
	font-weight:900;
	background-color:rgba(240, 240, 240, 0.5);
	color:#1C1C1C;
};

`

const Arrow = styled.div `
width:10px;
height:10px;
background-color:grey;
-webkit-clip-path:polygon(0 40%, 50% 85%, 100% 40%, 100% 55%, 50% 100%, 0 55%);
transform:rotate(-90deg);
`


const Menswear = styled.div ``

const Womenswear = styled.div ``

export default function Sell () {
	const photoWrapperSectionRef = useRef(null)
	const photoWrapperRef = useRef(null) 
	const photoInputRef = useRef(null)
	const [isUpload, setIsUpload] = useState({0:false,1:false, 2:false, 3:false, 4:false, 5:false})
	const photoAmount = [0, 1, 2, 3, 4, 5]
	const [dropdownActive, setDropdownActive] = useState(false)
	const [designers, setDesigners] = useState([])
	const [sizes, setSizes] = useState([])
	const [departments, setDepartments] = useState([])
	const [conditions, setConditions] = useState([])
	const [categories, setCategories] = useState([])
	const [subCategories, setSubCategories] = useState([])
	const dataRef = useRef({
		department_id:null,
		category_id:null,
		subCategory_id:null,
		designer_id:null,
		size_id:null,
		color:null,
		price:null,
		condition_id:null,
		itemName:null,
		description:null,
		image_1:null,
		image_2:null,
		image_3:null,
		image_4:null,
		image_5:null,
		image_6:null
	})
	const dropdownRef = useRef(null)
	const [departmentAndCategory, setDepartmentAndCategory] = useState('Department / Category')
	const [subCategory, setSubCategory] = useState('Sub-Category')
	const [designer, setDesigner] = useState('Designer')
	const [size, setSize] = useState('Size')
	const [itemName, setItemName] = useState('Item Name')
	const [price, setPrice] = useState('')
	const [color, setColor] = useState('Designer Color Name, i.e. "Frozen Yellow"')
	const [condition, setCondition] = useState('Condition')

	useEffect(() => {
		(async () => {
			const result = await fetch('http://localhost:5001/designers')
			const data = await result.json()
			setDesigners(() => {
				let newDesigners = []
				data.forEach(designer => newDesigners.push(designer))
				return newDesigners
			})
		})();
		(async () => {
			const result = await fetch('http://localhost:5001/size')
			const data = await result.json()
			setSizes(() => {
				let newSizes = []
				data.forEach(size => newSizes.push(size))
				return newSizes
			})
		})();
		(async () => {
			const result = await fetch('http://localhost:5001/departments')
			const data = await result.json()
			setDepartments(() => {
				let newDepartments = []
				data.forEach(department => newDepartments.push(department))
				return newDepartments
			})
		})();
		(async () => {
			const result = await fetch('http://localhost:5001/condition')
			const data = await result.json()
			setConditions(() => {
				let newCondition = []
				data.forEach(condition => newCondition.push(condition))
				return newCondition
			})
		})();
		(async () => {
			const result = await fetch('http://localhost:5001/categories')
			const data = await result.json()
			setCategories(() => {
				let newCategories = []
				data.forEach(category => newCategories.push(category))
				return newCategories
			})
		})();
		(async () => {
			const result = await fetch('http://localhost:5001/subCategories')
			const data = await result.json()
			setSubCategories(() => {
				let newSubCategories = []
				data.forEach(subcategory => newSubCategories.push(subcategory))
				return newSubCategories
			})
		})();
	},[])


	const getMap = (ref) => {
		if (!ref.current) {
			ref.current = new Map()
		}
		return ref.current
	}

	const getNode = (node, key, ref) => {
		const map = getMap(ref)
		if (node) {
			map.set(key, node)
		}
	}

	const handleImageUpload = (id) => {
		const reader = new FileReader()
		const photoWrapperMap = getMap(photoWrapperRef)
		const photoInputMap = getMap(photoInputRef)
		const photoWrapperNode = photoWrapperMap.get(id)
		const photoInputNode = photoInputMap.get(id)
		reader.readAsDataURL(photoInputNode.files[0])
		reader.addEventListener('load', () => {
			const uploaded_result = reader.result
			photoWrapperNode.style.backgroundImage = `url(${uploaded_result})`
			photoWrapperNode.style.backgroundSize = 'cover'
			photoWrapperNode.style.backgroundPosition = 'center'
			setIsUpload({...isUpload, id:true})
		})
	}

	const handleDropdown = (key) => {
		const categoryMap = getMap(dropdownRef)
		const categoryNode = categoryMap.get(key)
		if (categoryNode.style.display === '' || categoryNode.style.display === 'none') {
			categoryNode.style.display = 'block'
		} else {
			categoryNode.style.display = 'none'
		}
	}

	const handleOption = () => {
		setDropdownActive(!dropdownActive)
	}

	const handleCategoryChoose = (e, department, categoryName, department_id, category_id, key) => {
		e.stopPropagation()
		dataRef.current.department_id = department_id
		dataRef.current.category_id = category_id
		setDepartmentAndCategory(`${department} / ${categoryName}`)
		setDropdownActive(false)
		const Map = getMap(dropdownRef)
		const Node = Map.get(key)
		Node.style.display = 'none'
	}

	const handleOptionChoose = (subCategoryName, subCategoryId, key) => {
		if (key === 'subCategory') {
			setSubCategory(subCategoryName)
			dataRef.current.subCategory_id = subCategoryId
		} else if (key === 'designer') {
			setDesigner(subCategoryName)
			dataRef.current.designer_id = subCategoryId
		} else if (key === 'size') {
			setSize(subCategoryName)
			dataRef.current.size_id = subCategoryId
		} else {
			setCondition(subCategoryName)
			dataRef.current.condition_id = subCategoryId
		}

		const categoryMap = getMap(dropdownRef)
		const categoryNode = categoryMap.get(key)
		categoryNode.style.display = 'none !important'
	}

	const handleDepartmentClick = key => {
		const categoryMap = getMap(dropdownRef)
		const categoryNode = categoryMap.get(key)
		categoryNode.style.display = 'block'

	}

	const handleItenNameChange = e => {
		setItemName(e.target.value)
		dataRef.current.itemName = e.target.value
	}

	const handlePriceChange = e => {
		setPrice(e.target.value)
		dataRef.current.price = e.target.value
	}

	const handleColorClick = () => {
		setColor('')
	}

	const handleColorChange = e => {
		setColor(e.target.value)
		dataRef.current.color = e.target.value
	}

	const handleItenNameClick = () => {
		setItemName('')
	}

	const handleConditionClick = (key) => {
		setCondition('')
		const categoryMap = getMap(dropdownRef)
		const categoryNode = categoryMap.get(key)
		categoryNode.style.display = 'block'
	}

	const handleSaveDraft = () => {
		console.log(dataRef.current)
	}

	return (
		<>
			<Header />
			<Navbar />
			<SellWrapper>
				<Head>
					<Title>Add a New Listing</Title>
				</Head>
				<Body>
					<Details>
						<SectionTitle>Details</SectionTitle>
						<GridWrapper>
							<Detail onClick={handleOption}>{departmentAndCategory}
								<DepartmentAndCategory dropdownActive={dropdownActive}>
									<Option onClick={() => handleDepartmentClick('menswearCategory')}><Menswear>Menswear</Menswear><Arrow/></Option>
									<Option onClick={() => handleDepartmentClick('womenswearCategory')}><Womenswear>Womenswear</Womenswear><Arrow/></Option>
								</DepartmentAndCategory>
								<Dropdown ref={node => getNode(node, 'menswearCategory', dropdownRef)}>
									{categories
									.filter(category => category.department_id === 1)
									.map(category => 
									<Option key={category.id} onClick={e => handleCategoryChoose(e, 'Menswear', category.name, category.department_id, category.id, 'menswearCategory')}>
										{category.name}
									</Option>)}
								</Dropdown>
								<Dropdown ref={node => getNode(node, 'womenswearCategory', dropdownRef)}>
										{categories
										.filter(category => category.department_id === 2)
										.map(category => 
										<Option key={category.id} onClick={e => handleCategoryChoose(e, 'Womenswear',category.name , category.department_id, category.id, 'womenswearCategory')}>
											{category.name}
										</Option>)}
								</Dropdown>
							</Detail>
							<Detail onClick={() => handleDropdown('subCategory')}>{subCategory}
								<Dropdown ref={node => getNode(node, 'subCategory', dropdownRef)}>
										{subCategories
										.filter(subCategory => subCategory.category_id === dataRef.current.category_id)
										.map(subCategory => 
										<Option key={subCategory.id} onClick={() => handleOptionChoose(subCategory.name , subCategory.id, 'subCategory')}>
											{subCategory.name}
										</Option>)}
								</Dropdown>
							</Detail>
							<Detail onClick={() => handleDropdown('designer')}>{designer}
								<Dropdown ref={node => getNode(node, 'designer', dropdownRef)}>
										{designers
										.map(subCategory => 
										<Option key={subCategory.id} onClick={() => handleOptionChoose(subCategory.name , subCategory.id, 'designer')}>
											{subCategory.name}
										</Option>)}
								</Dropdown>
							</Detail>
							<Detail onClick={() => handleDropdown('size')}>{size}
								<Dropdown ref={node => getNode(node, 'size', dropdownRef)}>
										{sizes
										.map(size => 
										<Option key={size.id} onClick={() => handleOptionChoose(size.name , size.id, 'size')}>
											{size.name}
										</Option>)}
								</Dropdown>
							</Detail>
						</GridWrapper>
					</Details>
					<GridWrapper>
						<MoreDetail>
							<SectionTitle>Item Name</SectionTitle>
							<Item onChange={handleItenNameChange} onClick={handleItenNameClick} value={itemName}></Item>
						</MoreDetail>
						<MoreDetail>
							<SectionTitle>Color</SectionTitle>
							<Item onChange={handleColorChange} onClick={handleColorClick} value={color}></Item>
						</MoreDetail>
						<MoreDetail>
							<SectionTitle>Condition</SectionTitle>
							<Inputdiv onClick={() => handleConditionClick('condition')} value={condition}></Inputdiv>
							<Dropdown ref={node => getNode(node, 'condition', dropdownRef)}>
								{conditions
								.map(condition => 
								<Option key={condition.id} onClick={() => handleOptionChoose(condition.name , condition.id, 'condition')}>
									{condition.name}
								</Option>)}
							</Dropdown>
						</MoreDetail>
						<MoreDetail>
							<SectionTitle>Price</SectionTitle>
							<Item onChange={handlePriceChange} value={price}></Item>
						</MoreDetail>
					</GridWrapper>
					<Description>
						<SectionTitle>Description</SectionTitle>
						<DescriptionInput></DescriptionInput>
					</Description>
				</Body>
				<PhotoUploadSection>
					<Photo>
						{photoAmount.map(photo => 
						<PhotoWrapperSection key={photo}  ref={node => getNode(node, photo, photoWrapperSectionRef)}>
							{ Object.values(isUpload).filter( value => value ? <CancelIcon /> : null)}
							<PhotoWrapper ref={node => getNode(node, photo, photoWrapperRef)}>
								<PhotoInput ref={node => getNode(node, photo, photoInputRef)} onChange={() => handleImageUpload(photo)} type='file' accept='image/png, image/jpg'></PhotoInput></PhotoWrapper>
						</PhotoWrapperSection>
						)}
					</Photo>
				</PhotoUploadSection>
				<FooterWrapper>
					<Draft onClick={handleSaveDraft}>SAVE AS DRAFT</Draft>
					<Submit defaultValue='PUBLISH'></Submit>
				</FooterWrapper>
			</SellWrapper>

		</>
	)
}
